class Solution {
public:
    vector<int> maximumCount(vector<int>& nums, vector<vector<int>>& queries) {
        const int n = nums.size();
        vector<int> primeCount(100001, 0);
        for (int i = 2; i * i <= 100000; ++i) {
            if (primeCount[i] == 0) {
                for (int j = i * i; j <= 100000; j += i) {
                    primeCount[j] = 1;
                }
            }
        }
        for (int i = 2; i <= 100000; ++i) {
            if (primeCount[i] == 0) {
                primeCount[i] = 1;
            }
            primeCount[i] += primeCount[i - 1];
        }

        vector<int> count(n);
        for (int& num : nums) {
            count[num]++;
        }

        vector<int> prefixCount(n + 1);
        for (int i = 0; i < n; ++i) {
            prefixCount[i + 1] = prefixCount[i] + (primeCount[count[i]] - primeCount[count[i] - 1]);
        }

        vector<int> result;
        for (auto& query : queries) {
            int idx = query[0];
            int val = query[1];
            int oldVal = nums[idx];
            nums[idx] = val;

            count[oldVal]--;
            count[val]++;

            int maxCount = 0;
            for (int k = 0; k < n; ++k) {
                int leftCount = prefixCount[k + 1];
                int rightCount = prefixCount[n] - prefixCount[k + 1];
                maxCount = max(maxCount, leftCount + rightCount);
            }
            result.push_back(maxCount);
        }
        return result;
    }
};
